package com.homesynapse.event;

import java.time.Instant;
import java.util.Objects;

import com.homesynapse.platform.identity.Ulid;

/**
 * Bundles all caller-provided metadata for event publication via
 * {@link EventPublisher}.
 *
 * <p>An {@code EventDraft} captures the fields that the <em>caller</em> supplies
 * when producing an event. The remaining envelope fields are assigned by the
 * {@link EventPublisher} at append time:</p>
 *
 * <ul>
 *   <li>{@code eventId} — generated by the publisher using
 *       {@link com.homesynapse.platform.identity.UlidFactory} (monotonic)</li>
 *   <li>{@code ingestTime} — system clock at append time</li>
 *   <li>{@code subjectSequence} — next monotonic sequence for the subject</li>
 *   <li>{@code globalPosition} — SQLite {@code rowid} assigned at insert</li>
 *   <li>{@code categories} — derived from a static {@code eventType}→category
 *       mapping maintained by the publisher (Doc 01 §4.1, §4.4)</li>
 * </ul>
 *
 * <p>The causal context ({@link CausalContext}) is <em>not</em> part of the draft
 * because it determines which {@link EventPublisher} method to call: callers use
 * {@link EventPublisher#publishRoot(EventDraft)} for root events or
 * {@link EventPublisher#publish(EventDraft, CausalContext)} for derived events.
 * This two-method API enforces causality at compile time.</p>
 *
 * <p>Actor attribution is carried on the draft via {@link #actorRef()}, which the
 * publisher copies to the {@link EventEnvelope#actorRef()} field. For root events
 * the caller sets actorRef directly. For derived events the caller inherits
 * actorRef from the causing event's envelope.</p>
 *
 * <p>This record is immutable and safe to share across threads.</p>
 *
 * @param eventType     dotted category key identifying the event's type per the taxonomy
 *                      (Doc 01 §4.3); never {@code null} or blank
 * @param schemaVersion positive integer identifying the payload schema version; always
 *                      {@code >= 1}
 * @param eventTime     when the real-world occurrence happened, as reported by the event
 *                      source; {@code null} if the source has no reliable clock
 * @param subjectRef    identifies the domain object this event is about; never {@code null}
 * @param priority      delivery urgency and retention tier; never {@code null}
 * @param origin        evidence-based classification of the event's source; never {@code null}
 * @param payload       the event-type-specific data; never {@code null}
 * @param actorRef      the ULID of the person or actor attributable to this event;
 *                      {@code null} when no user is attributable (e.g., device-autonomous
 *                      or system-originated events). Copied to
 *                      {@link EventEnvelope#actorRef()} by the publisher.
 * @see EventPublisher
 * @see EventEnvelope
 */
public record EventDraft(
        String eventType,
        int schemaVersion,
        Instant eventTime,
        SubjectRef subjectRef,
        EventPriority priority,
        EventOrigin origin,
        DomainEvent payload,
        Ulid actorRef
) {

    /**
     * Validates all draft fields according to their documented constraints.
     * The {@code actorRef} field is nullable and requires no validation.
     *
     * @throws NullPointerException     if {@code eventType}, {@code subjectRef},
     *                                  {@code priority}, {@code origin}, or
     *                                  {@code payload} is {@code null}
     * @throws IllegalArgumentException if {@code eventType} is blank or
     *                                  {@code schemaVersion} is less than 1
     */
    public EventDraft {
        Objects.requireNonNull(eventType, "eventType must not be null");
        Objects.requireNonNull(subjectRef, "subjectRef must not be null");
        Objects.requireNonNull(priority, "priority must not be null");
        Objects.requireNonNull(origin, "origin must not be null");
        Objects.requireNonNull(payload, "payload must not be null");

        if (eventType.isBlank()) {
            throw new IllegalArgumentException("eventType must not be blank");
        }
        if (schemaVersion < 1) {
            throw new IllegalArgumentException(
                    "schemaVersion must be >= 1, got " + schemaVersion);
        }
    }
}
